\begin{theorem*}
    For every~$\theta \in \distsnc$ there exists~$F \in \asympspec(\T^k)$, such that~$F(\psi) = F^\theta(\psi) = F_\theta(\psi)$ for all~$\psi \in \Tnc^k$.
    Moreover, if~$\theta \in \distsnc \setminus \distssing$ then $ F \neq F_\theta$.
\end{theorem*}

