\begin{definition}
    \label{def:Tnck}
    A tensor $\psi \in \T^k$ is said to be laminar-quantum-robust if for all~$\theta \in \distsnc$, $F^\theta(\psi) = F_\theta(\psi)$.
    The set of laminar-quantum-robust tensors is denoted by $\Tnc^k$.
\end{definition}

